const body = $input.item.json.body || {};
const headers = $input.item.json.headers || {};
const fields = body.fields || {};
const email = (fields.email || '').toString().trim().toLowerCase();
const name  = (fields.name  || fields.full_name || '').toString().trim();
if (!email || !name) return { json: { _empty: true, status: 400, error: 'name + email required' } };
if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) return { json: { _empty: true, status: 400, error: 'invalid email' } };
if (body.consent_given !== true) return { json: { _empty: true, status: 400, error: 'CASL consent required' } };
// Build the leads payload. Crystallux Insurance Network is the MGA tenant.
const lead = {
  vertical_id: 'insurance',
  client_id: '6edc687d-07b0-4478-bb4b-820dc4eebf5d',
  full_name: name,
  email: email,
  phone: fields.phone || null,
  province: fields.province || null,
  lead_status: 'New Lead',
  source: body.source || 'marketing_site',
  source_url: body.page_url || null,
  source_referrer: body.referrer || null,
  notes: 'Insurance interest: ' + (fields.insurance_interest || fields.product || 'unspecified') +
         (fields.age_range      ? '; age ' + fields.age_range : '') +
         (fields.family         ? '; family ' + fields.family : '') +
         (fields.income_range   ? '; income ' + fields.income_range : '') +
         (fields.message        ? '\n' + fields.message : ''),
  consent_given_at: new Date().toISOString(),
  consent_method: 'web_form_checkbox',
  ip_address: headers['x-forwarded-for'] || headers['cf-connecting-ip'] || headers['x-real-ip'] || null,
  user_agent: headers['user-agent'] || null
};
const audit = {
  vertical_id: 'insurance',
  event_type: 'marketing_lead_captured',
  event_data: { source: body.source, page_url: body.page_url, fields_keys: Object.keys(fields), insurance_interest: fields.insurance_interest || null },
  ip_address: lead.ip_address,
  user_agent: lead.user_agent
};
return { json: { lead, audit } };

const row = $('Insert Lead').first().json;
const lead = Array.isArray(row) ? row[0] : row;
return { json: { ok: true, lead_id: lead && lead.id, message: 'Thanks — a licensed advisor will be in touch within one business day.' } };
